content:
\begin{equation}\label{eq:SQCD_EOM}
\begin{aligned}
    & \sum_{i=1}^F Q^i_\alpha \tilde{Q}_i^\beta = 0 \,,
    \qquad \sum_{\alpha = 1}^N Q^i_\alpha \Phi^\alpha_\beta = 0 \,, 
    \qquad \sum_{\alpha = 1}^N \Phi^\beta_\alpha \tilde{Q}^\alpha_i = 0 \,, \\ 
    & (\sigma_\alpha - X_i - \tfrac{\tau}{2}) Q^i_\alpha = 0 \,, 
    \qquad (X_i - \sigma_\alpha - \tfrac{\tau}{2}) \tilde{Q}_i^\alpha = 0 \,,
    \qquad [\sigma,\Phi]_\alpha^\beta + \tau \Phi_\alpha^\beta = 0 \,, \\  
    & [\Phi,\Phi^{\dagger}]_\alpha^\beta + \sum_{i=1}^{F}(Q^{i,\dagger}_\alpha Q^i_\beta  - \tilde{Q}^\alpha_i \tilde{Q}^{\beta,\dagger}_i ) = 
    \frac{\delta_\alpha^\beta}{2\pi} \bigg[ 
    - \eta +\frac{1}{2} \sum_{i=1}^F \Big(  \big| \sigma_\alpha - X_i - \frac{\tau}{2} \big| - \big| X_i - \sigma_\alpha - \frac{\tau}{2} \big| \Big) \\
    & \hspace{4cm}
    + \frac{1}{2}\sum_{\gamma=1}^N \Big( |\sigma_\alpha - \sigma_\gamma + \tau | - |\sigma_\gamma - \sigma_\alpha + \tau| \Big) 
    \bigg] \,.
\end{aligned}
\end{equation}

